const config = {
  "previewFeatures": [],
  "clientVersion": "7.8.0",
  "engineVersion": "3c6e192761c0362d496ed980de936e2f3cebcd3a",
  "activeProvider": "postgresql",
  "inlineSchema": "// Generator Configuration\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\n// Database Configuration\n// Note: DATABASE_URL should be set in your .env file\n// The connection URL is configured in prisma.config.ts\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ============================================================\n// ENUM DEFINITIONS\n// ============================================================\n\nenum UserRole {\n  Owner\n  Admin\n  Kurir\n}\n\nenum OrderStatus {\n  Pending\n  Dialokasikan\n  OnRoute\n  PickingUp\n  Delivering\n  Selesai\n  Done\n  Lunas\n  Dibatalkan\n  Canceled\n}\n\nenum CourierStatus {\n  Available\n  OnDuty\n  OffDuty\n}\n\nenum ExpenseStatus {\n  Pending\n  Approve\n  Reject\n}\n\nenum ReconciliationStatus {\n  Cocok\n  Selisih\n}\n\nenum ApprovalStatus {\n  Pending\n  Disetujui\n  Ditolak\n}\n\nenum RestockStatus {\n  Pending\n  Approved\n  Rejected\n}\n\nenum LogisticsStatus {\n  InTransit\n  DriverEnRoute\n  AwaitingVerification\n  Completed\n  CompletedDiscrepancy\n}\n\n// ============================================================\n// USER AUTHENTICATION & MANAGEMENT MODELS\n// ============================================================\n\nmodel User {\n  id_user    String   @id @default(cuid())\n  nama       String\n  email      String   @unique\n  password   String // bcrypt hashed\n  role       UserRole\n  id_cabang  String? // NULL for Owner (has access to all branches)\n  is_active  Boolean  @default(true)\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  // Relation: only for Admin/Kurir users\n  branch Branch? @relation(fields: [id_cabang], references: [id_cabang])\n\n  @@index([email])\n  @@index([id_cabang])\n  @@index([role])\n  @@map(\"users\")\n}\n\n// ============================================================\n// BRANCH MODEL\n// ============================================================\n\nmodel Branch {\n  id_cabang      String   @id\n  nama_cabang    String\n  alamat         String\n  latitude       Float\n  longitude      Float\n  kuota_harian   Int      @default(30)\n  kuota_terpakai Int      @default(0)\n  is_active      Boolean  @default(true)\n  omzet          Float    @default(0)\n  wilayah        String\n  created_at     DateTime @default(now())\n  updated_at     DateTime @updatedAt\n\n  // Relations\n  cashbook_entries CashBookEntry[]\n  couriers         Courier[]\n  orders           Order[]\n  expenses         Expense[]\n  monthly_budgets  MonthlyBudget[]\n  inventory_items  InventoryItem[]\n  reconciliations  ReconciliationLog[]\n  restock_requests RestockRequest[]\n  logistics_logs   LogisticsLog[]\n  customers        Customer[]\n  users            User[]\n\n  @@map(\"branches\")\n}\n\n// ============================================================\n// CASHBOOK MODEL\n// ============================================================\n\nmodel CashBookEntry {\n  id_jurnal      String   @id @default(cuid())\n  id_cabang      String\n  id_transaksi   String\n  nominal        Float\n  tipe           String // 'Pemasukan' or 'Pengeluaran'\n  deskripsi      String\n  tanggal_jurnal DateTime @default(now())\n  created_at     DateTime @default(now())\n\n  branch Branch @relation(fields: [id_cabang], references: [id_cabang])\n\n  @@index([id_cabang])\n  @@index([tipe])\n  @@map(\"cash_book_entries\")\n}\n\n// ============================================================\n// COURIER MODEL\n// ============================================================\n\nmodel Courier {\n  id_kurir      String   @id\n  id_cabang     String\n  nama_kurir    String\n  nomor_telepon String\n  is_available  Boolean  @default(true)\n  created_at    DateTime @default(now())\n  updated_at    DateTime @updatedAt\n\n  branch Branch  @relation(fields: [id_cabang], references: [id_cabang])\n  orders Order[]\n\n  @@index([id_cabang])\n  @@index([is_available])\n  @@map(\"couriers\")\n}\n\n// ============================================================\n// ORDER MODEL\n// ============================================================\n\nmodel Order {\n  id_order              String    @id\n  id_cabang             String\n  id_pelanggan          String    @default(\"\")\n  id_kurir              String?\n  alamat_penjemputan    String\n  alamat_pengantaran    String\n  latitude_penjemputan  Float\n  longitude_penjemputan Float\n  latitude_pengantaran  Float\n  longitude_pengantaran Float\n  status                String    @default(\"Pending\")\n  catatan               String?\n  berat_kg              Float?\n  total_harga           Float?\n  tanggal_order         DateTime  @default(now())\n  tanggal_selesai       DateTime?\n  customer_name         String?\n  customer_whatsapp     String?\n  service_type          String?\n  service_name          String? // For outlet orders\n  qty                   Float? // For outlet orders (pcs)\n  satuan                String? // For outlet orders (kg/pcs)\n  wilayah               String?\n  google_maps_url       String?\n  source                String? // 'whatsapp' or 'outlet'\n  assigned_by           String?\n  assigned_at           DateTime?\n  created_at            DateTime  @default(now())\n  updated_at            DateTime  @updatedAt\n\n  branch  Branch   @relation(fields: [id_cabang], references: [id_cabang])\n  courier Courier? @relation(fields: [id_kurir], references: [id_kurir])\n\n  @@index([id_cabang])\n  @@index([id_kurir])\n  @@index([status])\n  @@index([source])\n  @@index([tanggal_order])\n  @@map(\"orders\")\n}\n\n// ============================================================\n// EXPENSE MODEL\n// ============================================================\n\nmodel Expense {\n  id_expense        String    @id @default(cuid())\n  id_cabang         String\n  tanggal           DateTime\n  nominal           Float\n  deskripsi         String\n  kategori          String\n  bukti_nota_url    String    @default(\"\")\n  status            String    @default(\"Pending\")\n  tanggal_pengajuan DateTime  @default(now())\n  tanggal_approval  DateTime?\n  catatan_approval  String?\n  created_at        DateTime  @default(now())\n  updated_at        DateTime  @updatedAt\n\n  branch Branch @relation(fields: [id_cabang], references: [id_cabang])\n\n  @@index([id_cabang])\n  @@index([status])\n  @@index([kategori])\n  @@map(\"expenses\")\n}\n\n// ============================================================\n// MONTHLY BUDGET MODEL\n// ============================================================\n\nmodel MonthlyBudget {\n  id            String @id @default(cuid())\n  id_cabang     String\n  bulan         String\n  tahun         Int\n  pagu_anggaran Float\n  terpakai      Float  @default(0)\n\n  branch Branch @relation(fields: [id_cabang], references: [id_cabang])\n\n  @@unique([id_cabang, bulan, tahun])\n  @@index([id_cabang])\n  @@map(\"monthly_budgets\")\n}\n\n// ============================================================\n// INVENTORY ITEM MODEL\n// ============================================================\n\nmodel InventoryItem {\n  id               String @id @default(cuid())\n  id_cabang        String\n  item             String // 'Detergen', 'Pelembut', 'Plastik'\n  satuan           String\n  stok_saat_ini    Int\n  safety_threshold Int\n  max_capacity     Int\n\n  branch Branch @relation(fields: [id_cabang], references: [id_cabang])\n\n  @@unique([id_cabang, item])\n  @@index([id_cabang])\n  @@map(\"inventory_items\")\n}\n\n// ============================================================\n// RECONCILIATION LOG MODEL\n// ============================================================\n\nmodel ReconciliationLog {\n  id_rekonsiliasi String   @id @default(cuid())\n  id_cabang       String\n  tanggal         DateTime @default(now())\n  kas_digital     Float\n  kas_fisik       Float\n  selisih         Float\n  status          String // 'Cocok' or 'Selisih'\n  approval_status String   @default(\"Pending\")\n  catatan         String?\n  catatan_owner   String?\n  created_at      DateTime @default(now())\n\n  branch Branch @relation(fields: [id_cabang], references: [id_cabang])\n\n  @@index([id_cabang])\n  @@index([status])\n  @@index([approval_status])\n  @@map(\"reconciliation_logs\")\n}\n\n// ============================================================\n// RESTOCK REQUEST MODEL\n// ============================================================\n\nmodel RestockRequest {\n  id_request      String    @id @default(cuid())\n  id_cabang       String\n  nama_cabang     String\n  created_by      String\n  requested_items Json // { detergen?: number, pelembut?: number, plastik?: number }\n  status          String    @default(\"Pending\")\n  catatan         String?\n  reviewed_by     String?\n  reviewed_at     DateTime?\n  created_at      DateTime  @default(now())\n\n  branch Branch @relation(fields: [id_cabang], references: [id_cabang])\n\n  @@index([id_cabang])\n  @@index([status])\n  @@map(\"restock_requests\")\n}\n\n// ============================================================\n// LOGISTICS LOG MODEL\n// ============================================================\n\nmodel LogisticsLog {\n  id             String   @id @default(cuid())\n  id_cabang      String\n  sent_items     Json // StockCapacity { detergen, pelembut, plastik }\n  received_items Json? // StockCapacity\n  discrepancy    Json? // StockCapacity\n  status         String   @default(\"In-Transit\")\n  timestamp      DateTime @default(now())\n\n  branch Branch @relation(fields: [id_cabang], references: [id_cabang])\n\n  @@index([id_cabang])\n  @@index([status])\n  @@map(\"logistics_logs\")\n}\n\n// ============================================================\n// SERVICE TARIFF MODEL\n// ============================================================\n\nmodel ServiceTariff {\n  id_layanan       String  @id\n  nama_layanan     String\n  kategori         String // 'kiloan', 'satuan', 'bedcover'\n  satuan           String // 'kg', 'pcs'\n  harga_per_satuan Float\n  estimasi_hari    Int\n  is_active        Boolean @default(true)\n\n  @@map(\"service_tariffs\")\n}\n\n// ============================================================\n// EXPENSE CATEGORY MODEL\n// ============================================================\n\nmodel ExpenseCategory {\n  id   String @id @default(cuid())\n  name String @unique\n\n  @@map(\"expense_categories\")\n}\n\n// ============================================================\n// COURIER TASK SEQUENCE MODEL\n// ============================================================\n\nmodel CourierTaskSequence {\n  id       String @id @default(cuid())\n  id_kurir String\n  id_order String\n  urutan   Int\n\n  @@unique([id_kurir, id_order])\n  @@index([id_kurir])\n  @@map(\"courier_task_sequences\")\n}\n\n// ============================================================\n// INVENTORY ANOMALY MODEL\n// ============================================================\n\nmodel InventoryAnomaly {\n  id          String   @id @default(cuid())\n  id_cabang   String\n  nama_cabang String\n  item        String\n  stok_lama   Int\n  stok_baru   Int\n  alasan      String\n  timestamp   DateTime @default(now())\n\n  @@index([id_cabang])\n  @@map(\"inventory_anomalies\")\n}\n\n// ============================================================\n// CUSTOMER MODEL\n// ============================================================\n\nmodel Customer {\n  id_pelanggan    String   @id @default(cuid())\n  id_cabang       String\n  nama            String\n  whatsapp        String\n  alamat_maps     String\n  google_maps_url String?\n  created_at      DateTime @default(now())\n  updated_at      DateTime @updatedAt\n\n  branch Branch @relation(fields: [id_cabang], references: [id_cabang])\n\n  @@index([id_cabang])\n  @@map(\"customers\")\n}\n"
}

